import { derived, writable } from 'svelte/store';
import { gameSession } from './session';

export const gamePaused = writable(true);

// 从 session 快照派生的游戏状态 store，组件直接订阅即可
export const canUndo = derived(gameSession, ($session) => $session?.canUndo ?? false, false);
export const canRedo = derived(gameSession, ($session) => $session?.canRedo ?? false, false);
export const gameWon = derived(gameSession, ($session) => $session?.won ?? false, false);
